mapper.select:
SELECT ts, device_id AS deviceId, property, value_number AS valueNumber, value_string AS valueString, value_bool AS valueBool FROM device_telemetry WHERE tenant_id = #{tenantId} AND device_id = #{deviceId}
AND property = #{property}
AND ts >= CAST(#{startTime, jdbcType=VARCHAR} AS TIMESTAMPTZ)
AND ts <= CAST(#{endTime, jdbcType=VARCHAR} AS TIMESTAMPTZ)
ORDER BY ts DESC, property ASC
LIMIT #{limit}

